// 飞书长连接管理器 - 使用飞书官方 SDK 的 WSClient

import * as Lark from '@larksuiteoapi/node-sdk';

export interface FeishuConnectionState {
  connected: boolean;
  appId: string;
  appSecret: string;
  message: string;
  connectTime?: string;
}

export interface EventLog {
  id: string;
  timestamp: string;
  type: string;
  content: string;
}

class FeishuConnectionManager {
  private state: FeishuConnectionState = {
    connected: false,
    appId: '',
    appSecret: '',
    message: '未连接'
  };

  private logs: EventLog[] = [];
  private wsClient: any = null;
  private eventDispatcher: any = null;

  // 获取当前状态
  getState(): FeishuConnectionState {
    return { ...this.state };
  }

  // 获取日志
  getLogs(limit: number = 50): EventLog[] {
    return this.logs.slice(-limit);
  }

  // 添加日志
  private addLog(type: string, content: string) {
    const log: EventLog = {
      id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: new Date().toLocaleString('zh-CN'),
      type,
      content
    };
    this.logs.push(log);

    // 限制日志数量
    if (this.logs.length > 200) {
      this.logs = this.logs.slice(-200);
    }

    console.log(`[飞书] ${type}: ${content}`);
  }

  // 建立长连接
  async connect(appId: string, appSecret: string): Promise<{ success: boolean; error?: string }> {
    if (this.state.connected) {
      return { success: false, error: '已经建立连接，请先断开' };
    }

    this.state.appId = appId;
    this.state.appSecret = appSecret;

    try {
      this.addLog('INFO', '正在建立飞书 WebSocket 长连接...');

      // 创建飞书客户端
      const client = new Lark.Client({
        appId: appId,
        appSecret: appSecret,
      });

      // 创建事件处理器
      this.eventDispatcher = new Lark.EventDispatcher({
        loggerLevel: Lark.LoggerLevel.debug,
      }).register({
        // 处理消息接收事件
        'im.message.receive_v1': async (data: any) => {
          this.addLog('EVENT', `收到消息事件: ${JSON.stringify(data)}`);
        },
        // 处理其他事件
        'user.created_v1': async (data: any) => {
          this.addLog('EVENT', `收到用户创建事件: ${JSON.stringify(data)}`);
        },
        'contact.user.created_v3': async (data: any) => {
          this.addLog('EVENT', `收到联系人创建事件: ${JSON.stringify(data)}`);
        },
      });

      // 创建 WebSocket 客户端
      this.wsClient = new Lark.WSClient({
        appId: appId,
        appSecret: appSecret,
        loggerLevel: Lark.LoggerLevel.debug,
      });

      // 启动长连接
      await this.wsClient.start({
        eventDispatcher: this.eventDispatcher,
      });

      this.state.connected = true;
      this.state.message = 'WebSocket 长连接已建立';
      this.state.connectTime = new Date().toLocaleString('zh-CN');

      this.addLog('SUCCESS', 'WebSocket 长连接建立成功');
      this.addLog('INFO', '请在飞书开发者后台选择"长连接"订阅方式');

      return { success: true };
    } catch (error: any) {
      this.addLog('ERROR', `长连接建立失败: ${error.message}`);
      this.state.message = `连接失败: ${error.message}`;
      return { success: false, error: error.message };
    }
  }

  // 断开连接
  async disconnect(): Promise<{ success: boolean }> {
    try {
      this.addLog('INFO', '正在断开长连接...');

      // 停止 WebSocket 客户端
      if (this.wsClient) {
        try {
          await this.wsClient.stop();
        } catch (error) {
          this.addLog('WARN', `停止 WSClient 失败: ${error}`);
        }
        this.wsClient = null;
      }

      // 清理事件处理器
      this.eventDispatcher = null;

      // 重置状态
      this.state.connected = false;
      this.state.message = '已断开';
      this.state.connectTime = undefined;
      this.state.appId = '';
      this.state.appSecret = '';

      this.addLog('SUCCESS', '长连接已断开');

      return { success: true };
    } catch (error: any) {
      this.addLog('ERROR', `断开连接失败: ${error.message}`);
      return { success: false };
    }
  }

  // 发送消息到飞书
  async sendMessage(userId: string, content: string): Promise<boolean> {
    try {
      const client = new Lark.Client({
        appId: this.state.appId,
        appSecret: this.state.appSecret,
      });

      const response = await client.im.v1.message.create({
        params: {
          receive_id_type: 'open_id',
        },
        data: {
          receive_id: userId,
          msg_type: 'text',
          content: JSON.stringify({ text: content }),
        },
      });

      if (response.code === 0 && response.data) {
        this.addLog('SUCCESS', `消息发送成功: ${response.data.message_id}`);
        return true;
      } else {
        this.addLog('ERROR', `消息发送失败: ${response.msg}`);
        return false;
      }
    } catch (error: any) {
      this.addLog('ERROR', `消息发送异常: ${error.message}`);
      return false;
    }
  }
}

